// Actor that processes validated messages
class MessageProcessorActor extends Actor with ActorLogging {
  override def receive: Receive = {
    case msg: TextMessage =>
      log.info(s"Received text from ${msg.sender}: ${msg.content}")
      sender() ! PongMessage(System.currentTimeMillis())

    case msg: PingMessage =>
      log.info(s"Received ping at ${msg.timestamp}")
      sender() ! PongMessage(System.currentTimeMillis())

    case msg: PongMessage =>
      log.info(s"Received pong at ${msg.timestamp}")

    case unknown =>
      log.warning(s"Received unknown message type: ${unknown.getClass.getName}")
  }
